#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int shortestPath(vector<vector<int>>& maze, int sr, int sc, int dr, int dc) {
        int n = maze.size();
        int m = n ? maze[0].size() : 0;
        if (sr == dr && sc == dc) return 0;
        const int dirs[4][2] = {{1,0},{-1,0},{0,1},{0,-1}};
        queue<tuple<int,int,int>> q;
        q.emplace(sr, sc, 0);
        maze[sr][sc] = 1; // visited
        while (!q.empty()) {
            auto _tmp_binding_0 = q.front(); auto r = std::get<0>(_tmp_binding_0); auto c = std::get<1>(_tmp_binding_0); auto d = std::get<2>(_tmp_binding_0); q.pop();
            for (auto &dir : dirs) {
                int nr = r + dir[0];
                int nc = c + dir[1];
                if (nr>=0 && nr<n && nc>=0 && nc<m && maze[nr][nc]==0) {
                    if (nr==dr && nc==dc) return d+1;
                    maze[nr][nc] = 1;
                    q.emplace(nr,nc,d+1);
                }
            }
        }
        return -1;
    }
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int N,M;
    if(!(cin>>N>>M)) return 0;
    vector<vector<int>> maze(N, vector<int>(M));
    for(int i=0;i<N;i++){
        for(int j=0;j<M;j++) cin>>maze[i][j];
    }
    int Sr,Sc,Dr,Dc;
    cin>>Sr>>Sc>>Dr>>Dc;
    Solution sol;
    int ans = sol.shortestPath(maze, Sr, Sc, Dr, Dc);
    cout<<ans<<"\n";
    return 0;
}
